# 7. UI HELPERS
# ══════════════════════════════════════════════════════════
def card(children, style=None):
    base = {"background": CARD_BG, "border": f"1px solid {BORDER}",
            "borderRadius": "14px", "padding": "20px",
            "boxShadow": "0 1px 6px rgba(15,23,42,0.06)"}
    if style:
        base.update(style)
    return html.Div(children, style=base)

def kpi_card(label, value, sub="", color=ACCENT, icon=""):
    return card(html.Div([
        html.P([html.Span(icon + " " if icon else "", style={"fontSize": "16px"}), label],
               style={"color": TEXT_LITE, "fontSize": "11px", "fontWeight": "700",
                      "textTransform": "uppercase", "letterSpacing": "0.6px", "marginBottom": "6px"}),
        html.H2(value, style={"color": color, "fontSize": "28px", "fontWeight": "800",
                               "margin": "0", "lineHeight": "1"}),
        html.P(sub, style={"color": TEXT_MID, "fontSize": "12px",
                           "marginTop": "5px", "marginBottom": "0"}),
    ], style={"textAlign": "center"}), style={"padding": "18px 12px"})

def insight_panel(points, actions=None):
    elems = [html.Div([
        html.Div([html.Span("💡", style={"marginRight": "7px"}),
                  html.Span("Key Insights", style={"fontWeight": "700", "fontSize": "13px", "color": "#1D4ED8"})],
                 style={"marginBottom": "8px"}),
        html.Ul([html.Li(p, style={"fontSize": "12px", "color": TEXT_DARK,
                                    "marginBottom": "3px", "lineHeight": "1.55"}) for p in points],
                style={"paddingLeft": "18px", "margin": "0"}),
    ], style={"background": "#EFF6FF", "border": "1px solid #BFDBFE",
              "borderLeft": "4px solid #2563EB", "borderRadius": "10px",
              "padding": "14px 16px", "marginBottom": "10px"})]
    if actions:
        elems.append(html.Div([
            html.Div([html.Span("⚡", style={"marginRight": "7px"}),
                      html.Span("Actionable Recommendations",
                                style={"fontWeight": "700", "fontSize": "13px", "color": "#065F46"})],
                     style={"marginBottom": "8px"}),
            html.Ul([html.Li(a, style={"fontSize": "12px", "color": TEXT_DARK,
                                        "marginBottom": "3px", "lineHeight": "1.55"}) for a in actions],
                    style={"paddingLeft": "18px", "margin": "0"}),
        ], style={"background": "#ECFDF5", "border": "1px solid #A7F3D0",
                  "borderLeft": "4px solid #059669", "borderRadius": "10px", "padding": "14px 16px"}))
    return html.Div(elems, style={"marginTop": "14px"})

def section_header(title, sub=""):
    return html.Div([
        html.H5(title, style={"fontWeight": "700", "color": TEXT_DARK, "margin": "0", "fontSize": "15px"}),
        html.P(sub, style={"color": TEXT_MID, "fontSize": "12px", "margin": "2px 0 0 0"}) if sub else None,
    ], style={"borderLeft": f"3px solid {ACCENT}", "paddingLeft": "10px",
              "marginBottom": "14px", "marginTop": "22px"})

def graph_card(graph_id, height=380):
    return card(dcc.Graph(id=graph_id, config={"displayModeBar": False},
                          style={"height": f"{height}px"}))

