# 10. CALLBACKS
# ══════════════════════════════════════════════════════════

def _apply_filter(country, start, end):
    s, e = pd.to_datetime(start).date(), pd.to_datetime(end).date()
    mc = df_cust["InvoiceDate"].dt.date.between(s, e)
    mt = df_txn["InvoiceDate"].dt.date.between(s, e)
    if country != "ALL":
        mc &= df_cust["Country"] == country
        mt &= df_txn["Country"]  == country
    return df_cust[mc].copy(), df_txn[mt].copy()

def _apply_layout(fig, xtitle="", ytitle="", title=""):
    fig.update_layout(**BASE_LAYOUT, title=dict(text=title, font_size=13, x=0, xanchor="left"))
    fig.update_xaxes(**AXIS_STYLE, title_text=xtitle, title_font_size=11)
    fig.update_yaxes(**AXIS_STYLE, title_text=ytitle, title_font_size=11)
    return fig


@app.callback(
    Output("filter-country", "value"),
    Output("filter-dates",   "start_date"),
    Output("filter-dates",   "end_date"),
    Input("btn-reset", "n_clicks"),
    prevent_initial_call=True,
)
def reset_filters(_):
    return "ALL", MIN_DATE, MAX_DATE


# ── Overview KPIs ────────────────────────────────────────
@app.callback(
    Output("kpi-row", "children"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_kpis(country, start, end):
    dc, _ = _apply_filter(country, start, end)
    rev    = dc["Revenue"].sum()
    orders = dc["InvoiceNo"].nunique()
    custs  = int(dc["CustomerID"].nunique())
    aov    = rev / orders if orders else 0
    return dbc.Row([
        dbc.Col(kpi_card("Total Revenue",    f"£{rev:,.0f}",  "Gross sales (GBP)",   ACCENT,    "💰"), md=3),
        dbc.Col(kpi_card("Unique Orders",    f"{orders:,}",   "Invoices placed",     GREEN,     "🧾"), md=3),
        dbc.Col(kpi_card("Known Customers",  f"{custs:,}",    "With CustomerID",     "#7C3AED", "👤"), md=3),
        dbc.Col(kpi_card("Avg. Order Value", f"£{aov:,.2f}",  "Revenue per order",   AMBER,     "📦"), md=3),
    ], className="g-3")


# ── Monthly Revenue ──────────────────────────────────────
@app.callback(
    Output("chart-monthly", "figure"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_monthly(country, start, end):
    dc, _ = _apply_filter(country, start, end)
    m = dc.groupby("Month")["Revenue"].sum().reset_index()
    fig = go.Figure()
    fig.add_trace(go.Scatter(
        x=m["Month"], y=m["Revenue"], mode="lines+markers",
        line=dict(color=ACCENT, width=2.5),
        fill="tozeroy", fillcolor="rgba(37,99,235,0.07)",
        marker=dict(size=6, color=ACCENT),
        hovertemplate="<b>%{x|%b %Y}</b><br>Revenue: £%{y:,.0f}<extra></extra>",
    ))
    _apply_layout(fig, xtitle="Month", ytitle="Total Revenue (GBP £)")
    return fig


# ── Revenue by Country ───────────────────────────────────
@app.callback(
    Output("chart-country", "figure"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_country(country, start, end):
    dc, _ = _apply_filter(country, start, end)
    top = dc.groupby("Country")["Revenue"].sum().nlargest(10).reset_index()
    fig = go.Figure(go.Bar(
        x=top["Revenue"], y=top["Country"], orientation="h",
        marker=dict(color=top["Revenue"], colorscale="Blues", showscale=False),
        hovertemplate="<b>%{y}</b><br>Revenue: £%{x:,.0f}<extra></extra>",
    ))
    _apply_layout(fig, xtitle="Total Revenue (GBP £)", ytitle="")
    fig.update_yaxes(autorange="reversed", showgrid=False)
    return fig


