# ── Radar Chart ──────────────────────────────────────────
@app.callback(
    Output("chart-radar", "figure"),
    Input("seg-filter", "value"),
)
def update_radar(seg):
    cols = ["Recency", "Frequency", "Monetary", "AOV", "BasketSize", "Tenure"]
    # Simple ASCII-only labels — special chars / newlines break Plotly's polar axis
    cats = ["Recency (inv)", "Frequency", "Monetary", "AOV", "BasketSize", "Tenure"]

    radar = profile[cols].copy()
    radar["Recency"] = radar["Recency"].max() - radar["Recency"]   # invert: higher = better

    rng = radar.max() - radar.min()
    rng[rng == 0] = 1
    # Scale to [0.1, 0.9] — prevents weakest cluster collapsing to invisible point at origin
    radar_norm = ((radar - radar.min()) / rng) * 0.8 + 0.1

    def _rgba(hex_col, alpha):
        h = hex_col.lstrip("#")
        r, g, b = int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16)
        return f"rgba({r},{g},{b},{alpha})"

    fig = go.Figure()
    for ci, (idx, row) in enumerate(radar_norm.iterrows()):
        seg_name = str(profile.loc[idx, "Segment"])
        selected = (seg == "ALL" or seg_name == seg)
        color    = PALETTE[ci % len(PALETTE)]
        # Close polygon by repeating first point
        r_vals = row.tolist() + [row.tolist()[0]]
        t_vals = cats + [cats[0]]
        fig.add_trace(go.Scatterpolar(
            r=r_vals,
            theta=t_vals,
            fill="toself",
            name=seg_name,
            line=dict(color=color, width=3 if selected else 1),
            fillcolor=_rgba(color, 0.28 if selected else 0.05),
            hovertemplate="<b>" + seg_name + "</b><br>%{theta}: %{r:.2f}<extra></extra>",
        ))
    fig.update_layout(
        paper_bgcolor=CARD_BG,
        plot_bgcolor=CARD_BG,
        font=dict(family="'Inter','Segoe UI',sans-serif", color=TEXT_DARK, size=11),
        polar=dict(
            bgcolor=CARD_BG,
            radialaxis=dict(
                visible=True,
                range=[0, 1],
                showticklabels=False,
                gridcolor=BORDER,
            ),
            angularaxis=dict(
                gridcolor=BORDER,
                tickfont=dict(size=10),
            ),
        ),
        showlegend=True,
        legend=dict(
            orientation="h", x=0.5, xanchor="center", y=-0.15,
            font=dict(size=10), bgcolor="rgba(0,0,0,0)",
        ),
        margin=dict(l=55, r=55, t=30, b=60),
    )
    return fig


