# ── Transaction Timing by Cluster ────────────────────────
@app.callback(Output("chart-txn-timing", "figure"), Input("main-tabs", "active_tab"))
def update_txn_timing(_):
    timing = df_txn.groupby("TxnCluster").agg(
        Avg_Hour   =("Hour",    "mean"),
        Avg_DayCode=("DayCode", "mean"),
    ).reset_index().round(2)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    fig = make_subplots(rows=1, cols=2,
                        subplot_titles=["Avg. Hour of Day per Cluster",
                                        "Avg. Day of Week per Cluster"])
    fig.add_trace(go.Bar(
        x=[f"Cluster {c}" for c in timing["TxnCluster"]],
        y=timing["Avg_Hour"], marker_color=PALETTE[0],
        hovertemplate="<b>%{x}</b><br>Avg. Hour: %{y:.1f}:00<extra></extra>",
        showlegend=False,
    ), row=1, col=1)
    fig.add_trace(go.Bar(
        x=[f"Cluster {c}" for c in timing["TxnCluster"]],
        y=timing["Avg_DayCode"], marker_color=PALETTE[1],
        hovertemplate="<b>%{x}</b><br>Avg. Day Code: %{y:.2f} (0=Mon, 6=Sun)<extra></extra>",
        showlegend=False,
    ), row=1, col=2)
    fig.update_xaxes(showgrid=False, tickfont_size=10)
    fig.update_yaxes(showgrid=True, gridcolor=BORDER, zeroline=False,
                     linecolor=BORDER, tickfont_size=10)
    fig.update_yaxes(title_text="Average Hour (0–23)", row=1, col=1)
    fig.update_yaxes(title_text="Average Day Code (0=Mon, 6=Sun)", row=1, col=2)
    fig.update_layout(paper_bgcolor=CARD_BG, plot_bgcolor=CARD_BG,
                      font=dict(family="'Inter','Segoe UI',sans-serif", color=TEXT_DARK, size=12),
                      margin=dict(l=12, r=12, t=44, b=12))
    return fig


# ── Box Plots ────────────────────────────────────────────
@app.callback(
    Output("chart-boxplots", "figure"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_boxplots(country, start, end):
    _, dt = _apply_filter(country, start, end)
    cfg = [
        ("Quantity",  "Quantity (units per transaction line)", PALETTE[0]),
        ("UnitPrice", "Unit Price (GBP £ per unit)",           PALETTE[1]),
        ("Revenue",   "Revenue (GBP £ per transaction line)",  PALETTE[2]),
    ]
    fig = make_subplots(rows=1, cols=3, subplot_titles=[c[1] for c in cfg],
                        horizontal_spacing=0.08)
    for i, (col, label, color) in enumerate(cfg, 1):
        cap = dt[col].quantile(0.99)
        vals = dt[col].clip(upper=cap)
        fig.add_trace(go.Box(
            y=vals, name=label, marker_color=color,
            boxmean="sd", showlegend=False,
            hovertemplate=f"{col}: %{{y:.2f}}<extra></extra>",
        ), row=1, col=i)
        fig.update_yaxes(title_text=label, title_font_size=10,
                         showgrid=True, gridcolor=BORDER, zeroline=False,
                         linecolor=BORDER, tickfont_size=10, row=1, col=i)
        fig.update_xaxes(showgrid=False, tickfont_size=10, row=1, col=i)
    fig.update_layout(paper_bgcolor=CARD_BG, plot_bgcolor=CARD_BG,
                      font=dict(family="'Inter','Segoe UI',sans-serif", color=TEXT_DARK, size=11),
                      margin=dict(l=12, r=12, t=44, b=12))
    return fig


# ── AOV Trend ────────────────────────────────────────────
@app.callback(
    Output("chart-aov-trend", "figure"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_aov_trend(country, start, end):
    dc, _ = _apply_filter(country, start, end)
    m = dc.groupby("Month").agg(
        Revenue=("Revenue", "sum"),
        Orders =("InvoiceNo", "nunique"),
    ).reset_index()
    m["AOV"] = m["Revenue"] / m["Orders"]
    fig = go.Figure()
    fig.add_trace(go.Scatter(
        x=m["Month"], y=m["AOV"], mode="lines+markers",
        line=dict(color=GREEN, width=2.5),
        fill="tozeroy", fillcolor="rgba(5,150,105,0.07)",
        marker=dict(size=6, color=GREEN),
        hovertemplate="<b>%{x|%b %Y}</b><br>AOV: £%{y:,.2f}<extra></extra>",
    ))
    _apply_layout(fig, xtitle="Month", ytitle="Average Order Value (GBP £)")
    return fig


# ── Basket Size Trend ─────────────────────────────────────
@app.callback(
    Output("chart-basket-trend", "figure"),
    Input("filter-country", "value"),
    Input("filter-dates",   "start_date"),
    Input("filter-dates",   "end_date"),
)
def update_basket_trend(country, start, end):
    dc, _ = _apply_filter(country, start, end)
    inv_qty = dc.groupby(["Month", "InvoiceNo"])["Quantity"].sum().reset_index()
    m = inv_qty.groupby("Month")["Quantity"].mean().reset_index()
    m.columns = ["Month", "AvgBasket"]
    fig = go.Figure()
    fig.add_trace(go.Scatter(
        x=m["Month"], y=m["AvgBasket"], mode="lines+markers",
        line=dict(color=AMBER, width=2.5),
        fill="tozeroy", fillcolor="rgba(217,119,6,0.07)",
        marker=dict(size=6, color=AMBER),
        hovertemplate="<b>%{x|%b %Y}</b><br>Avg. Basket: %{y:.1f} units<extra></extra>",
    ))
    _apply_layout(fig, xtitle="Month", ytitle="Avg. Basket Size (units per order)")
    return fig


# ── Customer Behaviour Distributions ─────────────────────
@app.callback(Output("chart-cust-dist", "figure"), Input("seg-filter", "value"))
def update_cust_dist(seg):
    d = rfm_full if seg == "ALL" else rfm_full[rfm_full["Segment"] == seg]
    cfg = [
        ("BasketSize", d["BasketSize"].clip(upper=d["BasketSize"].quantile(0.99)),
         PALETTE[0], "Avg. Basket Size (units per transaction line)"),
        ("AOV",        d["AOV"].clip(upper=d["AOV"].quantile(0.99)),
         PALETTE[1], "Avg. Order Value (GBP £)"),
        ("Tenure",     d["Tenure"],
         PALETTE[2], "Customer Tenure (days between first & last purchase)"),
    ]
    fig = make_subplots(rows=1, cols=3, subplot_titles=[c[3] for c in cfg],
                        horizontal_spacing=0.09)
    for i, (name, vals, color, xt) in enumerate(cfg, 1):
        fig.add_trace(
            go.Histogram(x=vals, nbinsx=40, marker_color=color, opacity=0.8,
                         name=name, showlegend=False,
                         hovertemplate=f"Value: %{{x:.1f}}<br>Count: %{{y}}<extra>{name}</extra>"),
            row=1, col=i)
        fig.update_xaxes(title_text=xt, title_font_size=10,
                         showgrid=True, gridcolor=BORDER, zeroline=False,
                         linecolor=BORDER, tickfont_size=10, row=1, col=i)
        fig.update_yaxes(title_text="No. of Customers" if i == 1 else "",
                         showgrid=True, gridcolor=BORDER, zeroline=False,
                         linecolor=BORDER, tickfont_size=10, row=1, col=i)
    fig.update_layout(paper_bgcolor=CARD_BG, plot_bgcolor=CARD_BG,
                      font=dict(family="'Inter','Segoe UI',sans-serif", color=TEXT_DARK, size=11),
                      margin=dict(l=12, r=12, t=44, b=12))
    return fig


